import React, { useState } from 'react';
import { PageBanner, NavPills } from '../components/UIComponents';

const PHASES = [
  {
    num: 1, title: 'Policy Engine', gradient: '135deg,#3d1d63 0%,#5b2d90 55%,#b10f74 100%',
    features: [
      { title: 'Multi-Format Policy Import', desc: 'Import existing policies from Word, PDF, Excel, SharePoint libraries, or structured templates.' },
      { title: 'Structured Content Builder', desc: 'Drag-and-drop content builder with reusable content blocks.' },
      { title: 'AI-Assisted Drafting', desc: 'Generate policy drafts using GenAI trained on regulatory frameworks.' },
      { title: 'Clause Library', desc: 'Central repository of approved clauses that can be inserted into any policy document.' },
      { title: 'Conflict & Overlap Detection', desc: 'Automated checks for contradictions between policies.' },
    ],
    deliverables: 'Faster policy creation with AI-assisted drafting. Consistent policies using clause library. Reduced compliance gaps through automated conflict detection.',
  },
  {
    num: 2, title: 'Approval & Lifecycle Management', gradient: '135deg,#3d1d63 0%,#5b2d90 55%,#b10f74 100%',
    features: [
      { title: 'Configurable Approval Workflows', desc: 'Build approval chains with sequential, parallel, or conditional routing.' },
      { title: 'Version Control & History', desc: 'Full version history with diff viewer, rollback and branch capabilities.' },
      { title: 'Review Scheduling Engine', desc: 'Automated review reminders with configurable cycles.' },
      { title: 'Policy Retirement & Sunset', desc: 'End-of-life workflow to gracefully retire policies.' },
    ],
    deliverables: 'Accelerated approvals with smart routing. Audit-ready version control. Zero missed reviews through automated scheduling.',
  },
  {
    num: 3, title: 'Access Control & Security', gradient: '135deg,#3d1d63 0%,#5b2d90 55%,#b10f74 100%',
    features: [
      { title: 'Role-Based Access Control', desc: 'Department and policy group level access controls.' },
      { title: 'Document-Level Permissions', desc: 'Restrict certain annexures or clauses to small groups.' },
      { title: 'Comprehensive Access Logs', desc: 'Real-time monitoring and exportable audit reports.' },
      { title: 'Microsoft 365 Security Stack', desc: 'Encryption in transit and at rest, secure configuration.' },
    ],
    deliverables: 'Stronger data protection with SSO, MFA, and role-based access. Audit-ready access controls.',
  },
  {
    num: 4, title: 'White-Labelling', gradient: '135deg,#3d1d63 0%,#5b2d90 55%,#b10f74 100%',
    features: [
      { title: 'White-Labelled Portal', desc: 'Portal aligned with the bank\'s branding — logo, colours, fonts, layouts.' },
      { title: 'Role-Based Home Pages', desc: 'Personalized dashboards showing relevant policies, tasks, approvals.' },
      { title: 'Configurable Widgets', desc: '"Recently viewed", "Policies due for review", "My drafts" widgets.' },
      { title: 'Personal Collections', desc: 'Favourites, pinned documents and saved filters.' },
    ],
    deliverables: 'Higher user adoption with personalized dashboards. Consistent brand experience across the portal.',
  },
];

export default function PolicyPage({ onNavigate }) {
  const [openPhase, setOpenPhase] = useState(null);

  return (
    <div className="page-policy">
      <PageBanner icon="📋" badge="Policy Lifecycle" title="Policy Hub"
        subtitle="Centralized policy lifecycle management — from AI-assisted drafting to multi-stage approval, version control, compliance monitoring, and retirement." />
      <NavPills current="policy" onChange={onNavigate} />

      <div className="policy-phases">
        {PHASES.map((phase) => (
          <details key={phase.num} className="phase-accordion"
            open={openPhase === phase.num}
            onClick={(e) => { e.preventDefault(); setOpenPhase(openPhase === phase.num ? null : phase.num); }}>
            <summary className="phase-summary" style={{ background: `linear-gradient(${phase.gradient})` }}>
              <span className="phase-badge">{phase.num}</span>
              {phase.title}
            </summary>
            <div className="phase-body" onClick={(e) => e.stopPropagation()}>
              {phase.features.map((f, i) => (
                <div key={i} className="phase-feature">
                  <div className="feat-title">{f.title}</div>
                  <div className="feat-desc">{f.desc}</div>
                </div>
              ))}
              <div className="phase-deliverables">
                <div className="deliv-label">Key Deliverables</div>
                <div className="deliv-text">{phase.deliverables}</div>
              </div>
            </div>
          </details>
        ))}
      </div>
    </div>
  );
}
